import org.junit.jupiter.api.io.TempDir;

class PersistentSetTest {

	@Test
	void interruptedIteratorCloseDoesNotLeakReaderTxn(@TempDir File dataDir) throws Exception {
		PersistentSetFactory<Long> factory = new PersistentSetFactory<>(dataDir);
		Iterator<Long> iterator = null;

		try {
			PersistentSet<Long> set = factory.createSet("ids", PersistentSetTest::encodeLong,
					PersistentSetTest::decodeLong);
			assertTrue(set.add(1L));

			iterator = set.iterator();
			assertTrue(iterator.hasNext());
			assertEquals(1L, iterator.next());
			assertTrue(iterator instanceof AutoCloseable,
					"PersistentSet iterators must expose a close path for interrupted cleanup fallback");

			AutoCloseable closeable = (AutoCloseable) iterator;
			AtomicReference<Throwable> failure = new AtomicReference<>();
			AtomicBoolean interruptedAfterClose = new AtomicBoolean();

			Thread closer = new Thread(() -> {
				Thread.currentThread().interrupt();
				try {
					closeable.close();
				} catch (Throwable throwable) {
					failure.compareAndSet(null, throwable);
				} finally {
					interruptedAfterClose.set(Thread.currentThread().isInterrupted());
					Thread.interrupted();
				}
			}, "lmdb-persistent-set-interrupted-close-test");

			closer.start();
			closer.join(10_000);

			assertFalse(closer.isAlive());
			assertNull(failure.get());
			assertTrue(interruptedAfterClose.get());
			iterator = null;

			try (TxnManager.Txn ignored = factory.txnManager.createReadTxn()) {
				// Any abandoned close must have been drained before the next read txn is created.
			}
		} finally {
			closeIteratorForCleanup(iterator);
			factory.close();
		}
	}

	private static byte[] encodeLong(Long value) {
		return Long.toString(value).getBytes(StandardCharsets.UTF_8);
	}

	private static Long decodeLong(ByteBuffer buffer) {
		return Long.parseLong(StandardCharsets.UTF_8.decode(buffer.slice()).toString());
	}

	private static void closeIteratorForCleanup(Iterator<Long> iterator) throws Exception {
		if (iterator == null) {
			return;
		}
		if (iterator instanceof AutoCloseable) {
			((AutoCloseable) iterator).close();
			return;
		}
		Method closeMethod = iterator.getClass().getDeclaredMethod("close");
		closeMethod.setAccessible(true);
		closeMethod.invoke(iterator);
	}
}
